// 1. Recupera o valor e verifica se já está rodando
let valorPulsos = flow.get('valorPulsos') || 0;
let isProcessing = context.get('isProcessing') || false;

// Ignora quando o botão é solto
if (msg.payload === 1) return null; 

if (valorPulsos <= 0) {
    node.status({fill:"red", shape:"dot", text:"ERRO: Valor zerado!"});
    return null;
}

if (isProcessing) return null; // Trava contra duplo clique

context.set('isProcessing', true);

// --- FUNÇÕES DE TEMPO ---

// Função padrão para as pausas longas de 20ms (Reset e Finalização)
const delay = (ms) => new Promise(resolve => setTimeout(resolve, ms));

// Função HÍBRIDA para os Pulsos (Garante os 2ms precisos sem desconectar o Node-RED)
const pulsoRapido = async () => {
    // O setTimeout(0) obriga o Node-RED a "respirar" e enviar o comando elétrico para o pino AGORA
    await new Promise(resolve => setTimeout(resolve, 0)); 

    // O while garante que ele espere exatos 2 milissegundos antes de ir para o próximo passo
    let start = Date.now();
    while(Date.now() - start < 5) {} 
};

// --- EXECUÇÃO ---
(async function() {
    try {
        // ETAPA 1: RESET (Saída 1)
        node.status({fill:"yellow", shape:"dot", text:"Resetando Contador..."});

        node.send([{ payload: 1 }, null, null]);
        await delay(20);
        node.send([{ payload: 0 }, null, null]);
        await delay(20); 

        // ETAPA 2: PULSOS (Saída 2)
        node.status({fill:"blue", shape:"dot", text:`Enviando ${valorPulsos} Pulsos (2ms)...`});

        for (let i = 1; i <= valorPulsos; i++) {

            // Transistor ON (0V no CLP)
            node.send([null, { payload: 1 }, null]); 
            await pulsoRapido(); // Trava exatos 2ms

            // Transistor OFF (24V no CLP)
            node.send([null, { payload: 0 }, null]); 
            await pulsoRapido(); // Trava exatos 2ms
        }

        // ETAPA 3: FINALIZAÇÃO (Saída 3)
        node.status({fill:"yellow", shape:"dot", text:"Enviando Sinal Final..."});
        await delay(20);

        node.send([null, null, { payload: 1 }]);
        await delay(20);
        node.send([null, null, { payload: 0 }]);

        // CONCLUSÃO
        node.status({fill:"green", shape:"dot", text: `Sucesso: ${valorPulsos} pulsos enviados.`});

    } catch (erro) {
        node.error("Erro na execução: " + erro);
        node.status({fill:"red", shape:"dot", text:"Falha no envio."});
    } finally {
        // Libera o botão
        context.set('isProcessing', false);
    }
})();

return null;
